        hub: "vivir-en-suiza",
        slug: "actualidad-2026-04-26-9-las-multas-en-suiza-el-sistema-por-el-que-una-infraccion-de-trafico-puede-costar",
        readingTime: 2,
        dateUpdated: "26 avril 2026",
        featuredImage: "media/guides/actualidad-multas-trafico-suiza.jpg",
